using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);

// [Breaking change #1 — ValidateScopes enabled in Development]
// .NET 9 enables ValidateScopes by default in Development.
// A Singleton (CacheService) consuming a Scoped service (IUserService)
// is a captive dependency that now throws at startup.
// Fix: inject IServiceScopeFactory so CacheService can create scopes on demand.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddSingleton<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IServiceScopeFactory>()));

// [Breaking change #2 — HttpClientFactory uses SocketsHttpHandler by default]
// Casting PrimaryHandler to HttpClientHandler now throws InvalidCastException.
// Fix: use ConfigurePrimaryHttpMessageHandler with SocketsHttpHandler.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// [Breaking change #3 — HttpClientFactory redacts all header values in Trace logs]
// Trace-level header logging now redacts every value by default.
// Fix: allowlist the specific non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(name =>
        name != "X-Request-Id" &&
        name != "Accept" &&
        name != "Content-Type"));

// [Breaking change #4 — Forwarded Headers middleware ignores unknown proxies]
// X-Forwarded-* headers from proxies not in KnownProxies/KnownNetworks are now
// silently dropped. Fix: register your trusted reverse-proxy addresses.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: replace with your actual reverse-proxy IP(s) / CIDR ranges
    options.KnownProxies.Add(IPAddress.Parse("10.0.0.1"));
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

